// Simple QR Code generator
// This is a minimal QR code implementation for the file transfer app

(function(global) {
    'use strict';
    
    // QR Code generator
    function QRCode() {}
    
    // Generate QR code as canvas
    QRCode.toCanvas = function(canvas, text, options, callback) {
        if (typeof options === 'function') {
            callback = options;
            options = {};
        }
        
        options = options || {};
        const width = options.width || 256;
        const margin = options.margin || 4;
        
        try {
            // Create a simple QR-like pattern
            const size = 21; // QR code modules
            const moduleSize = Math.floor((width - margin * 2) / size);
            const actualWidth = size * moduleSize + margin * 2;
            
            canvas.width = actualWidth;
            canvas.height = actualWidth;
            
            const ctx = canvas.getContext('2d');
            
            // Fill background
            ctx.fillStyle = options.color?.light || '#FFFFFF';
            ctx.fillRect(0, 0, actualWidth, actualWidth);
            
            // Draw QR pattern
            ctx.fillStyle = options.color?.dark || '#000000';
            
            // Generate pattern based on text
            const pattern = generatePattern(text, size);
            
            for (let row = 0; row < size; row++) {
                for (let col = 0; col < size; col++) {
                    if (pattern[row][col]) {
                        const x = margin + col * moduleSize;
                        const y = margin + row * moduleSize;
                        ctx.fillRect(x, y, moduleSize, moduleSize);
                    }
                }
            }
            
            if (callback) callback(null);
            
        } catch (error) {
            if (callback) callback(error);
        }
    };
    
    // Generate QR code as data URL
    QRCode.toDataURL = function(text, options, callback) {
        if (typeof options === 'function') {
            callback = options;
            options = {};
        }
        
        const canvas = document.createElement('canvas');
        
        QRCode.toCanvas(canvas, text, options, function(error) {
            if (error) {
                if (callback) callback(error);
                return;
            }
            
            try {
                const dataURL = canvas.toDataURL('image/png');
                if (callback) callback(null, dataURL);
            } catch (err) {
                if (callback) callback(err);
            }
        });
    };
    
    // Simple pattern generator (not a real QR code algorithm)
    function generatePattern(text, size) {
        const pattern = [];
        
        // Initialize pattern
        for (let i = 0; i < size; i++) {
            pattern[i] = new Array(size).fill(false);
        }
        
        // Draw finder patterns (corners)
        drawFinderPattern(pattern, 0, 0);
        drawFinderPattern(pattern, size - 7, 0);
        drawFinderPattern(pattern, 0, size - 7);
        
        // Draw timing patterns
        for (let i = 8; i < size - 8; i++) {
            pattern[6][i] = (i % 2 === 0);
            pattern[i][6] = (i % 2 === 0);
        }
        
        // Simple data encoding based on text hash
        const hash = simpleHash(text);
        for (let i = 0; i < size; i++) {
            for (let j = 0; j < size; j++) {
                if (!pattern[i][j] && !isReservedArea(i, j, size)) {
                    pattern[i][j] = ((hash + i * size + j) % 3) === 0;
                }
            }
        }
        
        return pattern;
    }
    
    // Draw finder pattern (7x7 square)
    function drawFinderPattern(pattern, startRow, startCol) {
        for (let i = 0; i < 7; i++) {
            for (let j = 0; j < 7; j++) {
                const row = startRow + i;
                const col = startCol + j;
                
                if (row >= 0 && row < pattern.length && col >= 0 && col < pattern[0].length) {
                    pattern[row][col] = (i === 0 || i === 6 || j === 0 || j === 6 || 
                                      (i >= 2 && i <= 4 && j >= 2 && j <= 4));
                }
            }
        }
    }
    
    // Check if position is in reserved area
    function isReservedArea(row, col, size) {
        // Finder patterns
        if ((row < 9 && col < 9) || 
            (row < 9 && col >= size - 8) || 
            (row >= size - 8 && col < 9)) {
            return true;
        }
        
        // Timing patterns
        if (row === 6 || col === 6) {
            return true;
        }
        
        return false;
    }
    
    // Simple hash function
    function simpleHash(str) {
        let hash = 0;
        for (let i = 0; i < str.length; i++) {
            const char = str.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash; // Convert to 32-bit integer
        }
        return Math.abs(hash);
    }
    
    // Export
    global.QRCode = QRCode;
    
})(typeof window !== 'undefined' ? window : this);